Port.App<T>()는 [Port] 어트리뷰트 기반 초기화 방식 사용 시 반드시 첫 번째로 호출해야 합니다. [Port("sample")] public class SampleApp { } // 시작 시 (예: 생성자 또는 Program.cs) — 반드시 먼저 호출 Port.App<SampleApp>(); 전체 시작 예시​ [Port("sample")] public partial class MainWindow : Window { public MainWindow() { InitializeComponent(); try { Port.App<MainWindow>(); #if DEBUG var ioDoc = Port.Document<IOModel>(@"C:\Users\admin\Documents\IO.docx"); ioDoc.Where(v => v.Key.Contains("OnOff")).ToList() .ForEach(v => v.DataType = "Enum.OnOff"); ioDoc.Where(v => v.Key.Contains("Temp")).ToList() .ForEach(v => v.DataType = "f8"); if (ioDoc.Count > 0) { ioDoc.New(@"C:\Users\admin\Documents\sample\.page\io.page"); ioDoc.New(@"C:\Users\admin\Documents\sample\.net\io.cs"); } Port.Push("sample", new CustomEFEM()); Port.Push("sample", ioDoc.NewPage("Device")); Port.Pull("sample", @"D:\PORT\SampleArduinoLib\sample\Repo\pull"); #endif Port.Add<LoadportController, LoadportModel>("LP1"); Port.Add<LoadportController, LoadportModel>("LP2"); Port.OnReady += Port_OnReady; Port.Run(); } catch (Exception ex) { MessageBox.Show( $"{ex.Message}

Inner: {ex.InnerException?.Message}

Stack: {ex.StackTrace}"); } } }
